class Solution:
    def sumImbalanceNumbers(self, nums: List[int]) -> int:
        n = len(nums)
        total = 0

        for i in range(n):
            seen = set()
            imbalance = 0
            for j in range(i, n):
                num = nums[j]
                seen.add(num)
                if len(seen) == 1:
                    continue
                sarr = sorted(seen)
                for k in range(len(sarr) - 1):
                    if sarr[k + 1] - sarr[k] > 1:
                        imbalance += 1
            total += imbalance

        return total
